      type: 'createBalcony',
      id: 'hf-balcony-r',
      name: 'Loggia balcony right',
      wallId: 'hf-w-uf-s-r',
      elevationMm: F2F,
      projectionMm: 700,
      slabThicknessMm: 150,
      balustradeHeightMm: 1100,
    },
    {
      type: 'createBalcony',
      id: 'hf-balcony-c',
      name: 'Loggia balcony centre (chimney)',
      wallId: 'hf-w-uf-s-c',
      elevationMm: F2F,
      projectionMm: 700,
      slabThicknessMm: 150,
      balustradeHeightMm: 1100,
    },

    // === PHASE 7: DOCUMENTATION ===
    // Four camera presets matching the panels in target-house-vis-colored.png.
    {
      type: 'saveViewpoint',
      id: 'vp-main-iso',
      name: 'Main isometric (SSW — south facade + west gable, spec §5 front-left)',
      mode: 'orbit_3d',
