          heightMm: 19_400,
        },
        {
          viewportId: 'hf-vp-ga01-upper',
          label: 'First-floor plan',
          viewRef: 'plan:hf-pv-upper',
          detailNumber: '2',
          scale: '1:100',
          xMm: 30_000,
