    {
      type: 'updateElementProperty',
      elementId: 'hf-win-uf-trap',
      key: 'outlineKind',
      value: 'gable_trapezoid',
    },
    {
      type: 'updateElementProperty',
      elementId: 'hf-win-uf-trap',
      key: 'attachedRoofId',
      value: 'hf-roof-main',
