      heightMm: F2F,
      materialKey: 'white_cladding',
    },
    {
      type: 'createWall',
      id: 'hf-w-gf-w',
      name: 'GF west wall',
      levelId: 'hf-lvl-ground',
      start: { xMm: GF_X0, yMm: D },
      end: { xMm: GF_X0, yMm: 0 },
      thicknessMm: WALL_T,
      heightMm: F2F,
      materialKey: 'white_cladding',
    },

    // UF Shell Side Walls (Thick white band)
    {
      type: 'createWall',
      id: 'hf-w-uf-e',
      name: 'UF east shell wall',
      levelId: 'hf-lvl-upper',
      start: { xMm: UF_X1, yMm: 0 },
      end: { xMm: UF_X1, yMm: D },
      thicknessMm: SHELL_T,
      heightMm: 6000,
      materialKey: 'white_render',
    },
    {
      type: 'createWall',
      id: 'hf-w-uf-w',
      name: 'UF west shell wall',
      levelId: 'hf-lvl-upper',
      start: { xMm: UF_X0, yMm: D },
      end: { xMm: UF_X0, yMm: 0 },
      thicknessMm: SHELL_T,
      heightMm: 6000,
      materialKey: 'white_render',
    },
    {
      type: 'createWall',
      id: 'hf-w-uf-n',
      name: 'UF north wall',
      levelId: 'hf-lvl-upper',
      start: { xMm: UF_X1, yMm: D },
      end: { xMm: UF_X0, yMm: D },
      thicknessMm: WALL_T,
      heightMm: 6000,
      materialKey: 'white_render',
    },

    // UF Recessed Front Wall (at y=LOGGIA_SETBACK)
