      footprintMm: [
        { xMm: UF_X0, yMm: 0 },
        { xMm: UF_X1, yMm: 0 },
        { xMm: UF_X1, yMm: D },
        { xMm: UF_X0, yMm: D },
      ],
      heightMm: 4000,
      materialKey: 'white_render',
    },

    // === PHASE 2: SKELETON ===
    { type: 'deleteElement', elementId: 'hf-mass-gf' },
    { type: 'deleteElement', elementId: 'hf-mass-uf' },

    // GF Walls
    {
      type: 'createWall',
      id: 'hf-w-gf-s',
      name: 'GF south wall',
      levelId: 'hf-lvl-ground',
