    {
      type: 'createRoomOutline',
      id: 'hf-room-gf',
      name: 'Ground Floor Living',
      levelId: 'hf-lvl-ground',
      outlineMm: [
        { xMm: GF_X0 + 200, yMm: 200 },
        { xMm: GF_X1 - 200, yMm: 200 },
        { xMm: GF_X1 - 200, yMm: D - 200 },
        { xMm: GF_X0 + 200, yMm: D - 200 },
