      levelId: 'hf-lvl-upper',
      start: { xMm: CHIMNEY_X0, yMm: LOGGIA_SETBACK },
      end: { xMm: CHIMNEY_X0, yMm: 0 },
      thicknessMm: WALL_T,
      heightMm: 6000,
      materialKey: 'white_cladding',
