        { xMm: UF_X1 - 200, yMm: LOGGIA_SETBACK + 200 },
        { xMm: UF_X1 - 200, yMm: D / 2 - 200 },
        { xMm: UF_X0 + 200, yMm: D / 2 - 200 },
