        { xMm: UF_X1, yMm: D },
        { xMm: RIDGE_X, yMm: D },
      ],
    },

    // === PHASE 4: OPENINGS ===
    // Ground south windows
    {
      type: 'insertWindowOnWall',
      id: 'hf-win-gf-s-1',
      name: 'GF south window 1',
      wallId: 'hf-w-gf-s',
      alongT: 0.25,
      widthMm: 800,
      heightMm: 2000,
      sillHeightMm: 200,
      familyTypeId: 'window_casement_fixed',
    },
    {
      type: 'insertWindowOnWall',
      id: 'hf-win-gf-s-2',
      name: 'GF south window 2 (stair)',
      wallId: 'hf-w-gf-s',
      alongT: 0.5,
      widthMm: 800,
      heightMm: 2000,
      sillHeightMm: 200,
      familyTypeId: 'window_casement_fixed',
    },
    {
      type: 'insertDoorOnWall',
      id: 'hf-door-front',
      name: 'Front door',
      wallId: 'hf-w-gf-s',
      alongT: 0.9,
      widthMm: 1000,
      familyTypeId: 'door_hinged_single',
    },

    // Upper Front Openings
    {
      type: 'insertWindowOnWall',
      id: 'hf-win-uf-trap',
      name: 'Upper left trapezoidal window',
      wallId: 'hf-w-uf-s-l',
      alongT: 0.5,
      widthMm: 2500,
      heightMm: 2000,
      sillHeightMm: 500,
      familyTypeId: 'window_casement_fixed',
    },
    {
      type: 'updateElementProperty',
      elementId: 'hf-win-uf-trap',
      key: 'outlineKind',
      value: 'gable_trapezoid',
    },
    {
      type: 'updateElementProperty',
      elementId: 'hf-win-uf-trap',
      key: 'attachedRoofId',
      value: 'hf-roof-main',
    },

    // Curtain wall on the right
