        { xMm: RIDGE_X + 200, yMm: D - 200 },
      ],
      programmeCode: 'terrace',
    },

    // === PHASE 6: DETAIL ===
    // Chimney protrusion (Spec §3 Center volume)
    // It's a vertical siding volume in front of hf-w-uf-s-c
    {
      type: 'createWall',
