      type: 'createRailing',
      id: 'hf-rail-balcony',
      name: 'Upper balcony railing',
      pathMm: [
        { xMm: UF_X0 + SHELL_T, yMm: 50 },
        { xMm: CHIMNEY_X0, yMm: 50 },
